#!/usr/bin/env -S npx ts-node -r tsconfig-paths/register
/**
 * Example: Personal Access Token (PAT) - Environment Variables
 *
 * Description: Best practice for using PAT in production. The SDK automatically
 * reads credentials from environment variables.
 *
 * Prerequisites:
 * - Set DATABRICKS_HOST environment variable
 * - Set DATABRICKS_TOKEN environment variable
 *
 * Setup:
 * ```bash
 * export DATABRICKS_HOST="https://your-workspace.cloud.databricks.com"
 * export DATABRICKS_TOKEN="dapi..."
 * ```
 *
 * Run:
 * ```bash
 * npx ts-node examples/auth/pat-env-var.ts
 * ```
 */

import {WorkspaceClient} from "@databricks/sdk-experimental";

async function main() {
    // SDK automatically reads DATABRICKS_HOST and DATABRICKS_TOKEN
    const client = new WorkspaceClient({});

    try {
        const user = await client.currentUser.me();
        console.log(`✓ Successfully authenticated as: ${user.userName}`);
        console.log(`  User ID: ${user.id}`);

        console.log(`  Host: ${client.config.host}`);
    } catch (error) {
        console.error("✗ Authentication failed:", error);
        console.error(
            "\nMake sure you have set the following environment variables:"
        );
        console.error("  - DATABRICKS_HOST");
        console.error("  - DATABRICKS_TOKEN");
        process.exit(1);
    }
}

main().catch(console.error);
